(90, 1, '2026-04-10 18:55:55', '2026-04-10 15:55:55', '<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1.Hazırlık</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#1haz%C4%B1rl%C4%B1k\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.1 Neden Front-End Framework\'leri Var?✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#11-neden-front-end-frameworkleri-var\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.2 React vs. Vanilla JavaScript✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#12-react-vs-vanilla-javascript\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.3 React Nedir?✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#13-react-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.4 Geliştirme Ortamı✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#14-geli%C5%9Ftirme-ortam%C4%B1\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.5 Resmi Dokümantasyon✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#15-resmi-dok%C3%BCmantasyon\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Bileşenler ve JSX</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#2-bile%C5%9Fenler-ve-jsx\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.1 Bileşenler⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#21-bile%C5%9Fenler\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.2 JSX Nedir?⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#22-jsx-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.3 JSX Kuralları⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#23-jsx-kurallar%C4%B1\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.4 Props Mantığı⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#24-props-mant%C4%B1%C4%9F%C4%B1\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.5 Prop Destructuring⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#25-prop-destructuring\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.6 Fragments⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#26-fragments\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3.State ve \"Thinking in React\"</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#3state-ve-thinking-in-react\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">3.1 State Nedir?⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#31-state-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">3.2 Olay Yönetimi (Events)⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#32-olay-y%C3%B6netimi-events\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">3.3 useState Hook⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#33-usestate-hook\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">3.4 State Mekaniği⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#34-state-mekani%C4%9Fi\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">3.5 Thinking in React⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#35-thinking-in-react\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">3.6 Lifting State Up⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#36-lifting-state-up\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">3.7 Derived State⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#37-derived-state\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. React Nasıl Çalışır? (Arka Plan)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#4-react-nas%C4%B1l-%C3%A7al%C4%B1%C5%9F%C4%B1r-arka-plan\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">4.1 Virtual DOM Nedir?⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#41-virtual-dom-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">4.2 Bileşenler vs. Örnekler vs. Elementler⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#42-bile%C5%9Fenler-vs-%C3%B6rnekler-vs-elementler\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">4.3 Render Süreci⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#43-render-s%C3%BCreci\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">4.4 Diffing Algoritması⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#44-diffing-algoritmas%C4%B1\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">4.5 Key Prop⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#45-key-prop\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">4.6 Pure Components⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#46-pure-components\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">4.7 Batching⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#47-batching\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Effects, Data Fetching ve Hook Kuralları</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#5-effects-data-fetching-ve-hook-kurallar%C4%B1\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">5.1 Bileşen Yaşam Döngüsü (Lifecycle)⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#51-bile%C5%9Fen-ya%C5%9Fam-d%C3%B6ng%C3%BCs%C3%BC-lifecycle\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">5.2 useEffect Nedir?⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#52-useeffect-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">5.3 Dependency Array⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#53-dependency-array\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">5.4 Hook Kuralları⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#54-hook-kurallar%C4%B1\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">5.5 useRef Nedir?⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#55-useref-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">5.6 Custom Hooks⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#56-custom-hooks\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">6. Advanced State ve Routing (SPA)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#6-advanced-state-ve-routing-spa\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">6.1 useReducer Nedir?⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#61-usereducer-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">6.2 Single Page Applications (SPA)⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#62-single-page-applications-spa\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">6.3 Context API Nedir?⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#63-context-api-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">6.4 Custom Provider ve Hook⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#64-custom-provider-ve-hook\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">6.5 Compound Component Pattern⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#65-compound-component-pattern\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">7. Performans ve Redux</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#7-performans-ve-redux\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">7.1 Wasted Renders⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#71-wasted-renders\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">7.2 memo, useMemo ve useCallback⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#72-memo-usememo-ve-usecallback\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">7.3 Redux Nedir?⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#73-redux-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">7.4 Redux Toolkit (RTK)⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#74-redux-toolkit-rtk\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">7.5 Thunks⌛</h4>\n<!-- /wp:heading -->', 'Dökümantasyon', '', 'inherit', 'closed', 'closed', '', '40-revision-v1', '', '', '2026-04-10 18:55:55', '2026-04-10 15:55:55', '', 40, 'http://localhost/react.js/?p=90', 0, 'revision', '', 0),
(91, 1, '2026-04-10 18:56:51', '2026-04-10 15:56:51', '<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Karmaşa Yönetimi (Spaghetti Code Engelleyici)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Düz JavaScript ile küçük bir butona tıklanınca bir yazıyı değiştirmek kolaydır. Ancak aynı anda onlarca veri kaynağının değiştiği, kullanıcı girişlerinin kontrol edildiği ve dinamik içeriklerin aktığı bir projede kodlar kısa sürede birbirine girer. Framework\'ler, kodu <strong>modüler</strong> ve <strong>düzenli</strong> tutmak için belirli bir standart sunar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Bileşen (Component) Mantığı</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Framework\'lerin en büyük gücü \"bir kere yaz, her yerde kullan\" mantığıdır. Bir arama çubuğunu veya kullanıcı profil kartını bir <strong>bileşen</strong> olarak tasarlarsınız. Bu bileşeni projenin 50 farklı yerinde, kod tekrarı yapmadan kullanabilirsiniz. Tıpkı Lego parçaları gibi; her parçanın görevi bellidir ve birleşince büyük yapıyı oluşturur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Veri ve Arayüz Senkronizasyonu (State Management)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Eskiden bir veri değiştiğinde (örneğin sepete ürün eklendiğinde), o değişikliği ekrana yansıtmak için DOM (Document Object Model) elemanlarını manuel olarak bulup güncellemeniz gerekiyordu.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Framework\'ler ile:</strong> Siz sadece veriyi (state) güncellersiniz; framework, ekranda değişmesi gereken yerleri sizin yerinize otomatik olarak günceller. Bu, \"Reaktivite\" olarak adlandırılır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Performans ve Sanal DOM (Virtual DOM)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Tarayıcıdaki HTML elemanlarını doğrudan güncellemek maliyetli ve yavaş bir işlemdir. React gibi framework\'ler <strong>Virtual DOM</strong> kullanarak önce değişikliği hafızada simüle eder, ardından sadece gerçekten değişen kısımları tarayıcıya yansıtır. Bu da özellikle büyük uygulamalarda ciddi bir hız artışı sağlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Ekosistem ve Hız</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bir framework seçtiğinizde beraberinde devasa bir kütüphane desteği, hazır yönlendirme (routing) çözümleri ve test araçları gelir. Tekerleği her seferinde yeniden icat etmek yerine, topluluk tarafından test edilmiş güvenli yolları kullanarak çok daha hızlı ürün geliştirebilirsiniz.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu sayda kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla):</strong> <a href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks/Introduction\" target=\"_blank\" rel=\"noreferrer noopener\">\"Understanding client-side frameworks\"</a> </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React Resmi Dokümantasyonu:</strong> <a href=\"https://react.dev/learn/thinking-in-react\" target=\"_blank\" rel=\"noreferrer noopener\">\"Thinking in React\"</a> </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Neden Front-End Framework’leri Var?', '', 'inherit', 'closed', 'closed', '', '61-revision-v1', '', '', '2026-04-10 18:56:51', '2026-04-10 15:56:51', '', 61, 'http://localhost/react.js/?p=91', 0, 'revision', '', 0),
(93, 1, '2026-04-10 19:01:53', '2026-04-10 16:01:53', '<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Özellik</strong></td><td><strong>Vanilla JavaScript</strong></td><td><strong>React.js</strong></td></tr></thead><tbody><tr><td><strong>Yaklaşım</strong></td><td><strong>Emredici (Imperative):</strong> Adım adım ne yapılacağını söylersiniz.</td><td><strong>Bildirimsel (Declarative):</strong> Ekranın nasıl görünmesi gerektiğini söylersiniz.</td></tr><tr><td><strong>DOM Yönetimi</strong></td><td><strong>Real DOM(<strong>Document Object Model</strong>):</strong> Her değişiklikte tarayıcı tüm ağacı günceller (Yavaş olabilir).</td><td><strong>Virtual DOM(<strong>Document Object Model</strong>):</strong> Sadece değişen kısımlar hafızada hesaplanır ve güncellenir (Hızlı).</td></tr><tr><td><strong>Kod Yapısı</strong></td><td><strong>Karmaşık(Spaghetti):</strong> koda dönüşmeye müsaittir.</td><td><strong>Bileşen (Component) </strong>tabanlıdır; her parça bağımsızdır.</td></tr><tr><td><strong>Veri Bağlama</strong></td><td><strong>Manuel: </strong><br>Değişken değişince ekrandaki yazıyı elle güncellemelisiniz.</td><td><strong>Otomatik (Reaktif):</strong> Veri (State) değiştiğinde arayüz kendiliğinden güncellenir.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.Dev:</strong> <a href=\"https://react.dev/learn/thinking-in-react\" target=\"_blank\" rel=\"noreferrer noopener\">react.dev - Thinking in React</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla):</strong> <a href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks\" target=\"_blank\" rel=\"noreferrer noopener\">MDN - Client-side JavaScript frameworks</a></p>\n<!-- /wp:paragraph -->', 'React vs. Vanilla JavaScript', '', 'inherit', 'closed', 'closed', '', '64-revision-v1', '', '', '2026-04-10 19:01:53', '2026-04-10 16:01:53', '', 64, 'http://localhost/react.js/?p=93', 0, 'revision', '', 0),
(94, 1, '2026-04-10 19:02:58', '2026-04-10 16:02:58', '<!-- wp:paragraph -->\n<p><strong>React</strong>, kullanıcı arayüzleri (UI) oluşturmak için kullanılan, dünya genelinde en popüler <strong>açık kaynaklı JavaScript kütüphanesidir.</strong> 2013 yılında <strong>Meta (Facebook)</strong> tarafından geliştirilmeye başlanmıştır ve bugün milyonlarca web sitesi (Instagram, Netflix, Airbnb gibi) tarafından kullanılmaktadır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>İşte React\'i tanımlayan temel özellikler:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Bileşen Tabanlı Yapı (Component-Based)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React\'in kalbinde \"bileşenler\" yatar. Tüm web sayfasını tek bir büyük parça olarak değil, küçük ve bağımsız parçalar (butonlar, formlar, menüler) olarak düşünürsünüz.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Avantajı:</strong> Bir bileşeni bir kez yazıp projenin her yerinde tekrar tekrar kullanabilirsiniz. Bu, kodun bakımını kolaylaştırır ve hata payını azaltır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Bildirimsel Yaklaşım (Declarative)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React ile bir uygulamanın her durumu (state) için basit görünümler tasarlarsınız. Verileriniz değiştiğinde React, doğru bileşenleri otomatik olarak günceller ve render eder.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Düz JS farkı:</strong> \"Şu butona basınca şu yazıyı kırmızı yap\" demek yerine, \"Eğer durum \'aktif\' ise yazı kırmızı olsun\" dersiniz. Durum değiştiğinde React gerisini halleder.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Sanal DOM (Virtual DOM)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Web sayfalarındaki en yavaş işlem tarayıcının ekranı her seferinde yeniden çizmesidir (Real DOM). React, hafızada ekranın bir kopyasını (Virtual DOM) tutar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Nasıl Çalışır?</strong> Bir değişiklik olduğunda önce sanal kopyada işlem yapar, sonra gerçek ekranla karşılaştırır ve <strong>sadece değişen kısmı</strong> günceller. Bu da uygulamaların çok hızlı çalışmasını sağlar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. JSX (JavaScript XML)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React, HTML benzeri bir yapıyı JavaScript içinde yazmanıza olanak tanır. Buna <strong>JSX</strong> denir. Kodun okunabilirliğini artırır ve arayüzün mantığını görselleştirmenizi sağlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev: <a href=\"https://react.dev/learn\" target=\"_blank\" rel=\"noreferrer noopener\">Quick Start &amp; Thinking in React</a></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Meta Open Source:</strong> <a href=\"https://opensource.fb.com/projects/react/\" target=\"_blank\" rel=\"noreferrer noopener\">React - A JavaScript library for building user interfaces</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla):</strong> <a href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks/React_getting_started\" target=\"_blank\" rel=\"noreferrer noopener\">Getting started with React</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Wikipedia:</strong> <a href=\"https://en.wikipedia.org/wiki/React_(software)\" target=\"_blank\" rel=\"noreferrer noopener\">React (software)</a></p>\n<!-- /wp:paragraph -->', 'React Nedir', '', 'inherit', 'closed', 'closed', '', '67-revision-v1', '', '', '2026-04-10 19:02:58', '2026-04-10 16:02:58', '', 67, 'http://localhost/react.js/?p=94', 0, 'revision', '', 0),
(95, 1, '2026-04-10 19:03:16', '2026-04-10 16:03:16', '<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Özellik</strong></td><td><strong>Vanilla JavaScript</strong></td><td><strong>React.js</strong></td></tr></thead><tbody><tr><td><strong>Yaklaşım</strong></td><td><strong>Emredici (Imperative):</strong> Adım adım ne yapılacağını söylersiniz.</td><td><strong>Bildirimsel (Declarative):</strong> Ekranın nasıl görünmesi gerektiğini söylersiniz.</td></tr><tr><td><strong>DOM Yönetimi</strong></td><td><strong>Real DOM(<strong>Document Object Model</strong>):</strong> Her değişiklikte tarayıcı tüm ağacı günceller (Yavaş olabilir).</td><td><strong>Virtual DOM(<strong>Document Object Model</strong>):</strong> Sadece değişen kısımlar hafızada hesaplanır ve güncellenir (Hızlı).</td></tr><tr><td><strong>Kod Yapısı</strong></td><td><strong>Karmaşık(Spaghetti):</strong> koda dönüşmeye müsaittir.</td><td><strong>Bileşen (Component) </strong>tabanlıdır; her parça bağımsızdır.</td></tr><tr><td><strong>Veri Bağlama</strong></td><td><strong>Manuel: </strong><br>Değişken değişince ekrandaki yazıyı elle güncellemelisiniz.</td><td><strong>Otomatik (Reaktif):</strong> Veri (State) değiştiğinde arayüz kendiliğinden güncellenir.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev:</strong> <a href=\"https://react.dev/learn/thinking-in-react\" target=\"_blank\" rel=\"noreferrer noopener\">react.dev - Thinking in React</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla):</strong> <a href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks\" target=\"_blank\" rel=\"noreferrer noopener\">MDN - Client-side JavaScript frameworks</a></p>\n<!-- /wp:paragraph -->', 'React vs. Vanilla JavaScript', '', 'inherit', 'closed', 'closed', '', '64-revision-v1', '', '', '2026-04-10 19:03:16', '2026-04-10 16:03:16', '', 64, 'http://localhost/react.js/?p=95', 0, 'revision', '', 0),
(96, 1, '2026-04-10 19:04:17', '2026-04-10 16:04:17', '<!-- wp:paragraph -->\n<p>Resmi React dokümantasyonu (<strong>react.dev</strong>), sadece bir teknik kılavuz değil, aynı zamanda modern bir yazılım mimarisini öğrenmek için tasarlanmış bir eğitim aracıdır. Dokümantasyonu \"doğru\" şekilde okumak, öğrenme hızını iki katına çıkarabilir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>İşte React belgelerini en verimli kullanma stratejisi:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. \"Learn\" ve \"Reference\" Ayrımını Bilin</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dokümantasyon iki ana bölüme ayrılır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Learn (Öğren):</strong> Burası bir kitap gibidir. Kavramları sırasıyla anlatır. Eğer React\'e yeni başlıyorsanız veya bir konuyu (örneğin <code>useEffect</code>) derinlemesine anlamak istiyorsanız buradan başlamalısınız.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>API Reference (API Referansı):</strong> Burası bir sözlük gibidir. \"Bu fonksiyon tam olarak hangi parametreleri alıyordu?\" dediğinizde bakacağınız yerdir. Baştan sona okunmaz, ihtiyaç duyulunca başvurulur.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. \"Thinking in React\" Sayfasını Asla Atlamayın</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pek çok geliştirici doğrudan kod yazmaya çalışır. Ancak React ekibinin en çok üzerinde durduğu sayfa <a target=\"_blank\" rel=\"noreferrer noopener\" href=\"https://react.dev/learn/thinking-in-react\">Thinking in React</a> sayfasıdır. Bu sayfa size kod yazmayı değil, bir arayüze bakıp onu nasıl bileşenlere (component) ayıracağınızı ve veriyi nasıl yöneteceğinizi öğretir. Bu zihinsel yapıyı kurmadan kod yazmak, işleri zorlaştırır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. İnteraktif Kod Alanlarını (Sandboxes) Kullanın</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Yeni dokümantasyonun en büyük artısı, içinde gömülü kod editörlerinin olmasıdır. Bir kavram anlatılırken hemen altında çalışan bir örnek bulunur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Strateji:</strong> Sadece kodu okumayın. Editördeki bir değişkeni değiştirin, bir hata yapmaya çalışın ve sonucun tarayıcıda nasıl değiştiğini görün. Görsel hafıza, kod hafızasından daha güçlüdür.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. \"Pitfalls\" (Tuzaklar) Kutucuklarına Dikkat Edin</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dokümantasyonda genellikle sarı veya kırmızı çerçeveler içinde \"Pitfall\" başlıkları görürsünüz. Bunlar, topluluğun en çok yaptığı hataları ve performans kayıplarını içerir. Teoriyi okumaktan daha değerli olan şey, bu \"yapmamanız gerekenler\" listesidir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev:</strong> <a href=\"https://react.dev/learn\" target=\"_blank\" rel=\"noreferrer noopener\">React Learn Section</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Dan Abramov:</strong> <a href=\"https://overreacted.io/\" target=\"_blank\" rel=\"noreferrer noopener\">Overreacted.io</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Beta React Docs Feedback Thread (GitHub):</strong> <a href=\"https://github.com/reactjs/react.dev/issues\" target=\"_blank\" rel=\"noreferrer noopener\">GitHub reactjs/react.dev Issues</a></p>\n<!-- /wp:paragraph -->', 'Resmi Dokümantasyon', '', 'inherit', 'closed', 'closed', '', '71-revision-v1', '', '', '2026-04-10 19:04:17', '2026-04-10 16:04:17', '', 71, 'http://localhost/react.js/?p=96', 0, 'revision', '', 0),
(97, 1, '2026-04-10 19:05:11', '2026-04-10 16:05:11', '<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Pure React (CDN ile Kurulum)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Hiçbir kurulum yapmadan, tıpkı bir jQuery kütüphanesi gibi <code>&lt;script&gt;</code> etiketleri kullanarak React\'i HTML dosyanıza dahil edebilirsiniz.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Kullanım Amacı:</strong> React\'i hızlıca denemek veya mevcut bir sitenin küçük bir kısmına React eklemek.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Dezavantajı:</strong> Büyük projelerde yönetimi imkansızdır, JSX derlemesi tarayıcıda yapıldığı için yavaştır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Create-React-App (CRA) - <em>Artık Tavsiye Edilmiyor</em></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Yıllarca React\'e başlamanın standart yoluydu. Meta tarafından geliştirilen bu araç, Webpack ve Babel yapılandırmasını sizin yerinize yapıyordu.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Durum:</strong> <strong>Deprecated (Gözden Çıkarıldı).</strong> Resmi React dökümantasyonu artık CRA yerine modern araçların kullanılmasını öneriyor çünkü CRA çok ağır kalmaya ve yavaş derlemeye başladı.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Modern Kurulum: Vite.js</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bugün yeni bir React projesine başlamak için en çok tercih edilen araç <strong>Vite</strong>\'tır. Webpack yerine <strong>Esbuild</strong> kullanarak projeyi saniyeler içinde ayağa kaldırır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Neden Vite?</strong> \"Hot Module Replacement\" (HMR) hızı inanılmazdır. Kodda bir değişiklik yaptığınızda tarayıcı anında güncellenir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Framework Seçenekleri: Next.js ve Remix</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React ekibi artık sadece bir kütüphane değil, bir <strong>framework</strong> üzerinden kurulum yapılmasını öneriyor.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Next.js:</strong> Sunucu tarafı render (SSR), SEO uyumluluğu ve otomatik yönlendirme (routing) için endüstri standardıdır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Remix:</strong> Veri akışına ve kullanıcı deneyimine odaklanan modern bir alternatiftir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev:</strong> <a href=\"https://react.dev/learn/start-a-new-react-project\" target=\"_blank\" rel=\"noreferrer noopener\">Start a New React Project</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Vite.dev:</strong> <a href=\"https://vite.dev/guide/why.html\" target=\"_blank\" rel=\"noreferrer noopener\">Vite Guide - Why Vite?</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Meta Open Source Blog:</strong> <a href=\"https://www.google.com/search?q=https://github.com/reactjs/react.dev/pull/5487\" target=\"_blank\" rel=\"noreferrer noopener\">The Future of Create-React-App</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>State of JS Survey:</strong> <a href=\"https://2023.stateofjs.com/en-US/libraries/build_tools/\" target=\"_blank\" rel=\"noreferrer noopener\">State of JS - Build Tools</a></p>\n<!-- /wp:paragraph -->', 'Geliştirme Ortamı', '', 'inherit', 'closed', 'closed', '', '69-revision-v1', '', '', '2026-04-10 19:05:11', '2026-04-10 16:05:11', '', 69, 'http://localhost/react.js/?p=97', 0, 'revision', '', 0),
(98, 1, '2026-04-10 19:08:01', '2026-04-10 16:08:01', '<!-- wp:paragraph -->\n<p>React uygulamaları, <strong>bileşen (component)</strong> adı verilen bağımsız ve yeniden kullanılabilir parçalardan inşa edilir. Bileşenler, bir uygulamanın kullanıcı arayüzünü mantıksal parçalara ayırmanıza ve her parçayı kendi içinde yönetmenize olanak tanır. Kavramsal olarak bileşenler, rastgele girdileri (\"props\" olarak adlandırılır) kabul eden ve ekranda neyin görünmesi gerektiğini tanımlayan React öğelerini döndüren JavaScript fonksiyonlarıdır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1. Bileşen Tanımlama</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Modern React geliştirmede bileşenler genellikle <strong>Fonksiyonel Bileşenler (Function Components)</strong> olarak tanımlanır. Bir fonksiyonun React bileşeni sayılabilmesi için iki temel kurala uyması gerekir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>İsimlendirme:</strong> Bileşen ismi her zaman büyük harfle başlamalıdır (<code>&lt;Profile /></code> gibi). Küçük harfle başlayan etiketler HTML öğeleri (div, h1 vb.) için ayrılmıştır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Dönüş Değeri:</strong> Fonksiyon, tarayıcıda render edilecek bir JSX yapısı döndürmelidir.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Örnek Yapılandırma</h4>\n<!-- /wp:heading -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>function Welcome() {\n  return &lt;h1>Merhaba, React Dünyası!&lt;/h1>;\n}</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Bileşenlerin Kullanımı ve İç İçe Yerleştirme (Nesting)</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React bileşenleri diğer bileşenlerin içine yerleştirilebilir. Bu, karmaşık arayüzlerin basit parçalardan oluşturulmasını sağlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>function Button() {\n  return &lt;button>Gönder&lt;/button>;\n}\n\nexport default function Toolbar() {\n  return (\n    &lt;div>\n      &lt;p>İşlemi tamamlamak için butona tıklayın:&lt;/p>\n      &lt;Button />\n    &lt;/div>\n  );\n}</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Bileşenlerin Organizasyonu: Import ve Export</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bileşenlerin modüler kalması için genellikle ayrı dosyalarda tutulurlar. Bu süreçte JavaScript\'in <code>export</code> ve <code>import</code> sözdizimi kullanılır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Default Export:</strong> Bir dosyadan tek bir ana bileşen dışa aktarılırken kullanılır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Named Export:</strong> Bir dosyadan birden fazla yardımcı bileşen dışa aktarılırken kullanılır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Dosya Yapısı Örneği</h3>\n<!-- /wp:heading -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>// Gallery.jsx\nexport function Profile() {\n  return &lt;img src=\"avatar.jpg\" alt=\"Kullanıcı\" />;\n}\n\nexport default function Gallery() {\n  return (\n    &lt;section>\n      &lt;h1>Fotoğraf Galerisi&lt;/h1>\n      &lt;Profile />\n    &lt;/section>\n  );\n}</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">4. Teknik Prensipler ve Kısıtlamalar</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Pürüzsüz Render:</strong> Bileşenler \"pure\" (saf) fonksiyonlar gibi davranmalıdır. Aynı girdilerle her zaman aynı çıktıyı üretmeli ve render sırasında dış dünyadaki değişkenleri değiştirmemelidir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Kapsülleme (Encapsulation):</strong> Bir bileşen, kendi mantığını ve stilini barındırabilir ancak dışarıdan gelen veriye (props) müdahale edemez.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Bu sayfada kullanılan kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React Official Documentation:</strong> <a href=\"https://react.dev/learn/your-first-component\" target=\"_blank\" rel=\"noreferrer noopener\">Your First Component</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React Official Documentation:</strong> <a href=\"https://react.dev/learn/importing-and-exporting-components\" target=\"_blank\" rel=\"noreferrer noopener\">Importing and Exporting Components</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs:</strong> <a href=\"https://developer.mozilla.org/en-US/docs/Web/JavaScript/Guide/Modules\" target=\"_blank\" rel=\"noreferrer noopener\">JavaScript Modules</a></p>\n<!-- /wp:paragraph -->', 'Components(Bileşenler)', '', 'publish', 'closed', 'closed', '', 'componentsbilesenler', '', '', '2026-04-14 22:33:21', '2026-04-14 19:33:21', '', 0, 'http://localhost/react.js/?page_id=98', 0, 'page', '', 0),
(99, 1, '2026-04-10 19:08:01', '2026-04-10 16:08:01', '', 'Components(Bileşenler)', '', 'inherit', 'closed', 'closed', '', '98-revision-v1', '', '', '2026-04-10 19:08:01', '2026-04-10 16:08:01', '', 98, 'http://localhost/react.js/?p=99', 0, 'revision', '', 0);
